import { useEffect, useState, useRef } from "react";
import { useNavigate } from "react-router-dom";

export const useLogoutHandler = () => {
  const navigate = useNavigate();
  const [showLogoutModal, setShowLogoutModal] = useState(false);
  const backClickCountRef = useRef(0);

  // Handle logout
  const handleLogout = () => {
    localStorage.removeItem("token");
    localStorage.removeItem("user");
    setShowLogoutModal(false);
    backClickCountRef.current = 0; // Reset counter
    navigate("/login", { replace: true });
  };

  // Handle canceling logout (staying logged in)
  const handleStayLoggedIn = () => {
    setShowLogoutModal(false);
    // Reset counter when user chooses to stay
    backClickCountRef.current = 0;
  };

  // Prevent back button navigation to login page
  useEffect(() => {
    // Push initial state to create a history block
    window.history.pushState({ isLocked: true }, "", window.location.pathname);

    // Listen for back button clicks
    const handlePopState = () => {
      backClickCountRef.current++;

      if (backClickCountRef.current === 1) {
        // First back click: show logout modal
        setShowLogoutModal(true);
        // Push state again to prevent actual navigation
        window.history.pushState({ isLocked: true }, "", window.location.pathname);
      } else if (backClickCountRef.current >= 2) {
        // Second or subsequent back clicks: actually logout
        handleLogout();
      }
    };

    window.addEventListener("popstate", handlePopState);

    return () => {
      window.removeEventListener("popstate", handlePopState);
    };
  }, []);

  return { 
    handleLogout, 
    showLogoutModal, 
    setShowLogoutModal: handleStayLoggedIn,
    forceLogout: handleLogout 
  };
};
